#include <vector>
#include <omp.h>

/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Parallelise the outer loop.  The work for each i is independent
       and the compiler/CPU can keep the inner loops in the
       register, so we just need a straightforward parallel for. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sumA = 0.0;
        double sumB = 0.0;
        /* Use local pointers to speed up the inner loop access. */
        const std::vector<double>& Ai = A[i];
        const std::vector<double>& Bi = B[i];
        for (int j = 0; j < n; ++j) {
            double xj = x[j];
            sumA += Ai[j] * xj;
            sumB += Bi[j] * xj;
        }
        tmp[i] = sumA;
        y[i]   = alpha * sumA + beta * sumB;
    }
}
