/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    const double coeff = 1.0 / 3.0;

    double* restrict Ap = A.data();
    double* restrict Bp = B.data();

    /* OpenMP parallelise the two inner loops separately.
       Each iteration writes to a distinct element of the destination
       array, so there are no write conflicts. */
    for (int t = 0; t < tsteps; ++t) {
        /* First sweep: A -> B */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            Bp[i] = coeff * (Ap[i - 1] + Ap[i] + Ap[i + 1]);
        }

        /* Second sweep: B -> A */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            Ap[i] = coeff * (Bp[i - 1] + Bp[i] + Bp[i + 1]);
        }
    }
}
