/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
		    std::vector<std::vector<double>>& L,
		    std::vector<double>& x,
		    std::vector<double>& b)
{
    /* For better cache behaviour we avoid using temporary std::vector
       objects in the inner loop: we access the matrix row directly
       via a raw pointer.  Since the routine is inherently serial
       (each new x[i] depends on all previous x[j]), no parallelism is
       possible.  The code below preserves the exact numerical
       behaviour of the reference implementation while reducing
       indirection and unnecessary temporary loads. */
    for (int i = 0; i < n; ++i) {
        double xi = b[i];

        const double* row = L[i].data();           // L[i][0 .. i-1] accessed via row[j]
        for (int j = 0; j < i; ++j) {
            xi -= row[j] * x[j];
        }
        xi /= row[i];                               // row[i] == L[i][i]

        x[i] = xi;
    }
}
