void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    // Parallelise the outermost loop over rows of C.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Pre‑multiply the lower triangle of C by beta.
        for (int j = 0; j <= i; ++j) {
            C[i][j] *= beta;
        }

        // Use pointer arithmetic for inner loops.
        double* C_row = C[i].data();
        const double* A_row_i = A[i].data();

        for (int k = 0; k < m; ++k) {
            const double aik = A_row_i[k];
            const double* A_col_k = &A[0][k];  // first element of column k

            for (int j = 0; j <= i; ++j) {
                C_row[j] += alpha * aik * A_col_k[j];
            }
        }
    }

    // Symmetrise the result (C is symmetric).  Filling upper triangle
    // from the already computed lower triangle guarantees that the
    // final matrix has exactly the same values as the original code.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            C[i][j] = C[j][i];
        }
    }
}
