static inline int min_int(int a, int b) { return a < b ? a : b; }

void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Create a contiguous flat array to speed up cache usage
    std::vector<int> flat(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(path[i].begin(), path[i].end(), flat.data() + i * n);

    // Floyd‑Warshall with OpenMP on the i‑loop
    for (int k = 0; k < n; ++k) {
        int k_offset = k * n;
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            int i_offset = i * n;
            int aik = flat[i_offset + k];
            for (int j = 0; j < n; ++j) {
                int new_val = aik + flat[k_offset + j];
                int cur = flat[i_offset + j];
                flat[i_offset + j] = min_int(cur, new_val);
            }
        }
    }

    // Copy results back to the 2‑D vector
    for (int i = 0; i < n; ++i)
        std::copy(flat.begin() + i * n, flat.begin() + (i + 1) * n,
                  path[i].begin());
}
