/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    /* 1.   Avoid virtual indexing on std::vector<vector<double>>.
     *     Store row pointers for fast access. */
    std::vector<double*> a_rows(m), b_rows(m);
    for (int i = 0; i < m; ++i) {
        a_rows[i] = A[i].data();
        b_rows[i] = B[i].data();
    }

    /* 2.   Basic blocking for cache friendliness.  Block size is tuned
     *     for typical L1/L2/cache lines on an x86‑64 CPU. */
    const int BLOCK = 64;

    /* 3.   Parallelise the outermost loop over rows of B (i).  Each
     *     iteration is independent because B[i][j] only depends on
     *     B[k][j] for k>i. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* bi = b_rows[i];
        /* Process columns in blocks to keep inner loop length small
         * and enable SIMD throughput. */
        for (int jb = 0; jb < n; jb += BLOCK) {
            int jend = std::min(jb + BLOCK, n);
            /* Accumulate contribution from lower rows of A. */
            for (int k = i + 1; k < m; ++k) {
                double aik = a_rows[k][i];          // A[k][i]
                double* bk = b_rows[k];
                for (int j = jb; j < jend; ++j) {
                    bi[j] += aik * bk[j];
                }
            }
            /* Scale by alpha. */
            for (int j = jb; j < jend; ++j) {
                bi[j] *= alpha;
            }
        }
    }
}
