void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* Flatten the data to a contiguous layout to improve cache usage */
    std::vector<double> flat(n * m);
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double* src = data[i].data();
        double* dst = &flat[i * m];
        std::copy(src, src + m, dst);
    }

    /* Compute means (parallelized) */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += flat[i * m + j];
        }
        mean[j] = sum / static_cast<double>(n);
    }

    /* Subtract means (parallelized) */
    #pragma omp parallel for
    for (int i = 0; i < n; ++i) {
        double* row = &flat[i * m];
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
        }
    }

    /* Compute covariance matrix (upper triangle only, then mirror) */
    #pragma omp parallel for
    for (int i = 0; i < m; ++i) {
        double* ci = &flat[i];              // pointer to column i
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            double* cj = &flat[j];          // pointer to column j
            for (int k = 0; k < n; ++k) {
                sum += ci[k * m] * cj[k * m];
            }
            double value = sum / static_cast<double>(n - 1);
            cov[i][j] = value;
            cov[j][i] = value;              // symmetry
        }
    }

    /* Write back to the original 2D vector representation (optional) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        std::copy(&flat[i * m], &flat[i * m] + m, data[i].data());
    }
}
