/* Optimised kernel – identical behaviour, multi‑threaded and cache‑friendly */
#include <vector>
#include <omp.h>
#include <cstring>   // for std::memset

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum) {

    /* Allocate a working array once per thread.  It is reused for all
       (r,q) iterations. */
    static thread_local std::vector<double> localSum;
    if (localSum.size() < static_cast<size_t>(np))
        localSum.resize(np);

    /* Collapse the outer loops so that the work is distributed evenly
       across the 8 hardware threads. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            /* Zero the local accumulator once per (r,q) pair. */
            std::memset(localSum.data(), 0, sizeof(double) * np);

            /* Perform the MAC: sum[p] += A[r][q][s] * C4[s][p]  */
            for (int s = 0; s < np; ++s) {
                double a_val = A[r][q][s];
                double* c_ptr = C4[s].data();          // pointer to C4[s][0]
                double* sum_ptr = localSum.data();     // pointer to sum[0]
                for (int p = 0; p < np; ++p)
                    sum_ptr[p] += a_val * c_ptr[p];
            }

            /* Copy the result back into A[r][q][p] */
            double* dst = A[r][q].data();   // pointer to A[r][q][0]
            std::memcpy(dst, localSum.data(), sizeof(double) * np);
        }
    }
}
