/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B)
{
    const double coeff = 0.2;
    const int end = n - 1;                 // indices i,j < n-1

    for (int t = 0; t < tsteps; ++t) {
        // First update B from A
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < end; ++i) {
            // Pointers to current, previous and next rows of A
            double* Arow   = A[i].data();
            double* Arowp1 = A[i+1].data();
            double* Arowm1 = A[i-1].data();

            double* Brow   = B[i].data();
            for (int j = 1; j < end; ++j) {
                // compute the stencil using row pointers for speed
                Brow[j] = coeff * (Arow[j] + Arow[j-1] + Arow[j+1]
                                  + Arowp1[j] + Arowm1[j]);
            }
        }

        // Then update A from B
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < end; ++i) {
            double* Brow   = B[i].data();
            double* Browp1 = B[i+1].data();
            double* Browm1 = B[i-1].data();

            double* Arow   = A[i].data();
            for (int j = 1; j < end; ++j) {
                Arow[j] = coeff * (Brow[j] + Brow[j-1] + Brow[j+1]
                                   + Browp1[j] + Browm1[j]);
            }
        }
    }
}
