#include <vector>
#include <cmath>
#include <cstddef>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    constexpr double eps = 0.1;          // as in the original code
    constexpr double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* --------------------------------------------------------------------
       1) Compute column means -------------------------------------------------
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / n;
    }

    /* --------------------------------------------------------------------
       2) Compute column standard deviations -----------------------------------
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum_sq = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double diff = data[i][j] - mu;
            sum_sq += diff * diff;
        }
        double sigma = std::sqrt(sum_sq / n);
        stddev[j] = (sigma <= eps) ? 1.0 : sigma;
    }

    /* --------------------------------------------------------------------
       3) Normalise data ------------------------------------------------------
       (subtract mean and divide by (sqrt(n)*stddev))
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double val = data[i][j] - mean[j];
            val *= inv_sqrt_n / stddev[j];
            data[i][j] = val;
        }
    }

    /* --------------------------------------------------------------------
       4) Compute correlation matrix -----------------------------------------
       corr[i][j] = 1.0 for i==j, otherwise dot product of columns i and j
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;                     // diagonal element
        for (int j = i + 1; j < m; ++j) {
            double dot = 0.0;
            for (int k = 0; k < n; ++k) dot += data[k][i] * data[k][j];
            corr[i][j] = dot;
            corr[j][i] = dot;                 // symmetry
        }
    }
}
