/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    // Replace expensive double indirection with raw pointers.
    std::vector<double*> row_ptr;
    row_ptr.reserve(n);
    for (auto& row : A)
        row_ptr.push_back(row.data());

    for (int i = 0; i < n; ++i) {
        double* Ai = row_ptr[i];

        /* Lower triangle (j < i) - sequential because each Ai[j]
           depends on previous elements of the same row. */
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            double* Ak = Ai;
            double* Akj;
            for (int k = 0; k < j; ++k) {
                Akj = row_ptr[k];
                sum += Ak[k] * Akj[j];
            }
            Ai[j] -= sum;
            Ai[j] /= Ai[j * 0 + j];  // Ai[j] after subtraction is A[i][j]
        }

        /* Upper triangle (j >= i) - independent across j after the
           lower triangle has finished.  We can parallelise this inner
           loop because no two threads write the same element.        */
        #pragma omp parallel for schedule(static)
        for (int j = i; j < n; ++j) {
            double sum = 0.0;
            for (int k = 0; k < i; ++k) {
                sum += Ai[k] * row_ptr[k][j];
            }
            Ai[j] -= sum;
        }
    }
