        const double ui2 = u2[i];
        for (int j = 0; j < n; ++j)
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
    }

    /* ------------------------------------------------------------------
     *  2 :  x += beta * A^T * y
     * ------------------------------------------------------------------ */
    /* Compute contribution of each column of A^T (i.e., each row of A)
     * into a separate temporary array to avoid false sharing of x. */
