/*
   Optimised QR decomposition (Modified Gram–Schmidt)
   Uses contiguous host‑side arrays and OpenMP for parallelisation.
   The public API remains unchanged – the harness can pass the original
   std::vector<std::vector<double>> containers.
*/

static inline void copy_to_contiguous(const std::vector<std::vector<double>>& src,
                                      double* dst, std::size_t m, std::size_t n)
{
    for (std::size_t i = 0; i < m; ++i) {
        std::memcpy(dst + i * n, src[i].data(), n * sizeof(double));
    }
}

static inline void copy_from_contiguous(const double* src,
                                        std::vector<std::vector<double>>& dst,
                                        std::size_t m, std::size_t n)
{
    for (std::size_t i = 0; i < m; ++i) {
        std::memcpy(dst[i].data(), src + i * n, n * sizeof(double));
    }
}

/*
   Main kernel
*/
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    /* Allocate contiguous working buffers */
    std::vector<double> Acont(m * n);
    std::vector<double> Qcont(m * n);
    std::vector<double> Rcont(n * n, 0.0);

    /* Copy input into contiguous buffer */
    copy_to_contiguous(A, Acont.data(), m, n);

    /* Main Modified Gram–Schmidt loop */
    for (int k = 0; k < n; ++k) {
        /* 1. Compute norm of column k */
        double norm2 = 0.0;
        #pragma omp parallel for reduction(+:norm2) schedule(static)
        for (int i = 0; i < m; ++i) {
            double val = Acont[i * n + k];
            norm2 += val * val;
        }
        Rcont[k * n + k] = std::sqrt(norm2);

        /* 2. Normalize column k to obtain Q */
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Qcont[i * n + k] = Acont[i * n + k] / Rcont[k * n + k];
        }

        /* 3. Orthogonalise remaining columns */
        for (int j = k + 1; j < n; ++j) {
            /* Compute R[k][j] = Q_k · A_j */
            double dot = 0.0;
            #pragma omp parallel for reduction(+:dot) schedule(static)
            for (int i = 0; i < m; ++i) {
                dot += Qcont[i * n + k] * Acont[i * n + j];
            }
            Rcont[k * n + j] = dot;

            /* Update A_j := A_j - Q_k * R[k][j] */
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                Acont[i * n + j] -= Qcont[i * n + k] * dot;
            }
        }
    }

    /* Copy results back into the original containers */
    copy_from_contiguous(Acont.data(), A, m, n);
    copy_from_contiguous(Rcont.data(), R, n, n);
    copy_from_contiguous(Qcont.data(), Q, m, n);
}
