/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/*
  Original version by Dave Wonnacott at Haverford College <davew@cs.haverford.edu>,
  with help from Allison Lake, Ting Zhou, and Tian Jin,
  based on algorithm by Nussinov, described in Allison Lake's senior thesis.
*/

void kernel_nussinov(int n,
                     std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {
    // Flatten the 2D table into a 1D array for cache‑friendly access.
    std::vector<int> flat(n * n, 0);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flat[i * n + j] = table[i][j];

    auto match = [](int b1, int b2) { return (b1 + b2 == 3) ? 1 : 0; };

    // Dynamic programming over increasing gaps.  Parallelise the inner
    // loop over i for each fixed gap.  Each iteration of the loop
    // writes only into entries with j-i = gap, so there is no
    // cross‑iteration dependency.
    for (int gap = 1; gap < n; ++gap) {
        #pragma omp parallel for schedule(static)
        for (int i = 0; i + gap < n; ++i) {
            int j = i + gap;
            int idx = i * n + j;

            // table[i][j] starts at its current value (copied from input).
            int best = flat[idx];

            // Dependence from left neighbour
            best = std::max(best, flat[i * n + (j - 1)]);
            // Dependence from upper neighbour
            best = std::max(best, flat[(i + 1) * n + j]);

            // Match or skip when j-1 >= 0 and i+1 < n
            if (i + 1 < n) { // already guaranteed
                int val = flat[(i + 1) * n + (j - 1)];
                if (i < j - 1) {
                    val += match(seq[i], seq[j]);
                }
                best = std::max(best, val);
            }

            // Split the interval at k
            for (int k = i + 1; k < j; ++k) {
                best = std::max(best,
                               flat[i * n + k] + flat[(k + 1) * n + j]);
            }

            flat[idx] = best;
        }
    }

    // Copy the result back to the original 2D table view.
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            table[i][j] = flat[i * n + j];
}
