    Grid2D<double> ex_fast(nx, ny), ey_fast(nx, ny), hz_fast(nx, ny);

    /* 2. Copy original data into fast arrays.  We do this only once
     *    before the main loop because the kernel expects the
     *    grids to have the same dimensions. */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < nx; ++i) {
        for (int j = 0; j < ny; ++j) {
            ex_fast(i, j) = ex[i][j];
            ey_fast(i, j) = ey[i][j];
            hz_fast(i, j) = hz[i][j];
