/* Optimised Durbin recursion kernel.
 *
 * The algorithm is fundamentally serial (each iteration depends on the
 * previous one), but the inner loops can be vectorised.  We use raw
 * pointers for the vectors and AVX2 intrinsics to get the best
 * performance on a modern x86‑64 CPU.  The function has the same
 * behavioural signature as the reference implementation.
 */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Allocate temporary storage once (size n, aligned)
    double* z = static_cast<double*>(
        _mm_malloc(static_cast<size_t>(n) * sizeof(double), 32));

    // Initialise first element
    y[0] = -r[0];
    double beta = 1.0;
    double alpha = -r[0];

    // Main loop
    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = Σ_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        int i = 0;
        // Vectorised part
        const int simd_width = 4;  // 4 doubles per AVX2 vector
        const int simd_end = k / simd_width * simd_width;
        __m256d vec_sum = _mm256_setzero_pd();

        for (; i < simd_end; i += simd_width) {
            __m256d vr = _mm256_loadu_pd(&r[k - i - 1]);          // r[k-i-1], r[k-i-2], ...
            __m256d vy = _mm256_loadu_pd(&y[i]);                  // y[i], y[i+1], ...
            vec_sum = _mm256_fmadd_pd(vr, vy, vec_sum);
        }
        // Horizontal addition of vector
        alignas(32) double tmp[4];
        _mm256_store_pd(tmp, vec_sum);
        sum += tmp[0] + tmp[1] + tmp[2] + tmp[3];

        // Remaining non‑vectorised tail
        for (; i < k; ++i) {
            sum += r[k - i - 1] * y[i];
        }

        alpha = -(r[k] + sum) / beta;

        // Compute z[i] = y[i] + alpha * y[k-i-1]
        i = 0;
        for (; i < simd_end; i += simd_width) {
            __m256d vy1  = _mm256_loadu_pd(&y[i]);                    // y[i..i+3]
            __m256d vy2  = _mm256_loadu_pd(&y[k - i - simd_width]);   // y[k-i-4 .. k-i-1]
            __m256d valpha = _mm256_set1_pd(alpha);
            __m256d vz = _mm256_fmadd_pd(valpha, vy2, vy1);
            _mm256_storeu_pd(&z[i], vz);
        }
        // Tail
        for (; i < k; ++i) {
            z[i] = y[i] + alpha * y[k - i - 1];
        }

        // Copy z back to y
        std::memcpy(&y[0], &z[0], k * sizeof(double));
        y[k] = alpha;
    }

    _mm_free(z);
