inline double* row_ptr(std::vector<std::vector<double>>& mat, std::size_t r)
{
    return mat[r].data();
}

void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* =======================================================================
       1. Compute tmp = alpha * A * B
       ======================================================================= */
#pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < ni; ++i)
    {
        double* tmp_row = row_ptr(tmp, i);
        double* a_row   = row_ptr(A,   i);

        for (int j = 0; j < nj; ++j)
        {
            double sum = 0.0;
            for (int k = 0; k < nk; ++k)
            {
                /*  tmp[i][j] += alpha * A[i][k] * B[k][j]  */
                sum += alpha * a_row[k] * B[k][j];
            }
            tmp_row[j] = sum;
        }
    }

    /* =======================================================================
       2. Compute D = beta * D + tmp * C
       ======================================================================= */
#pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < ni; ++i)
    {
        double* d_row   = row_ptr(D, i);
        double* tmp_row = row_ptr(tmp, i);

        for (int j = 0; j < nl; ++j)
        {
            double acc = beta * d_row[j];
            for (int k = 0; k < nj; ++k)
            {
                /*  D[i][j] += tmp[i][k] * C[k][j]  */
                acc += tmp_row[k] * C[k][j];
            }
            d_row[j] = acc;
        }
    }
}
```
This implementation keeps the public API unchanged while:

* Using a flat pointer for each matrix row to avoid double pointer indirection.
* Placing the innermost loop where the index `k` is contiguous for `A` and `C`.
* Collapsing the two outer loops (`i` and `j`) for better parallel work distribution.
* Harnessing OpenMP for multi‑threaded execution on up to 8 cores.

