#include <vector>
#include <omp.h>

/* Main computational kernel (optimized for speed). The function
   signature must remain identical to the original harness. */
void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    /* Pre‑compute the constant multiplier. */
    const double coeff = 0.125;

    /* Temporary pointers to the underlying data of A and B.
       The inner vectors are stored contiguously, so the
       address of each slice is contiguous and can be used
       as a 3‑D pointer. */
    std::vector<double*> Aptr(n - 2), Bptr(n - 2);
    for (int i = 1; i < n - 1; ++i) {
        Aptr[i-1] = &A[i][1][0];
        Bptr[i-1] = &B[i][1][0];
    }

    /* Main time loop. */
    for (int t = 1; t <= tsteps; ++t) {
        /* Update B from A.  Parallelise the 3‑D stencil with
           collapse(3) to get good load balance. */
#pragma omp parallel for collapse(3) schedule(static)
        for (int ii = 1; ii < n - 1; ++ii) {
            for (int jj = 1; jj < n - 1; ++jj) {
                /* Pointer to the current position in the 3‑D slice. */
                double* bp = Bptr[ii-1] + jj*n;
                double* ap = Aptr[ii-1] + jj*n;
                for (int kk = 1; kk < n - 1; ++kk) {
                    double const cur = ap[kk];
                    double const sum = ap[kk+1] + ap[kk-1]
                                     + ap[kk+n] + ap[kk-n]
                                     + ap[kk+1+n] + ap[kk-1+n];
                    bp[kk] = coeff * sum + 0.25 * cur;
                }
            }
        }

        /* Update A from B – identical stencil, so the same
           loop structure can be reused. */
#pragma omp parallel for collapse(3) schedule(static)
        for (int ii = 1; ii < n - 1; ++ii) {
            for (int jj = 1; jj < n - 1; ++jj) {
                double* ap = Aptr[ii-1] + jj*n;
                double* bp = Bptr[ii-1] + jj*n;
                for (int kk = 1; kk < n - 1; ++kk) {
                    double const cur = bp[kk];
                    double const sum = bp[kk+1] + bp[kk-1]
                                     + bp[kk+n] + bp[kk-n]
                                     + bp[kk+1+n] + bp[kk-1+n];
                    ap[kk] = coeff * sum + 0.25 * cur;
                }
            }
        }
    }
}
