    const float k = 1.0f - std::exp(-alpha) * (1.0f - std::exp(-alpha)) /
                     (1.0f + 2.0f * static_cast<float>(alpha) * std::exp(-alpha) -
                      std::exp(2.0f * static_cast<float>(alpha)));

    const float a1 = k, a5 = k;
    const float exp_aminus = std::exp(-alpha);
    const float a2 = a6 = k * exp_aminus * (static_cast<float>(alpha) - 1.0f);
    const float a3 = a7 = k * exp_aminus * (static_cast<float>(alpha) + 1.0f);
    const float exp_minus2 = exp_aminus * exp_aminus;
    const float a4 = a8 = -k * exp_minus2;

    const float b1  = std::pow(2.0f, -static_cast<float>(alpha));
    const float b2  = -exp_minus2;
    const float c1  = 1.0f, c2 = 1.0f;

#pragma omp parallel for
    for (int i = 0; i < w; ++i) {
