#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1  = 2.0;
    const double B2  = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    const int innerSize = n - 2;   // number of interior points in j direction

#pragma omp parallel for schedule(static) shared(u,v,p,q)
    for (int t = 0; t < tsteps; ++t)
    {
        /* First sweep (vertical) */
#pragma omp for schedule(static)
        for (int i = 1; i < n-1; ++i)
        {
            double* v_row0    = v[0].data();
            double* v_rowN     = v[n-1].data();
            double* p_row      = p[i].data();
            double* q_row      = q[i].data();
            const double* u_row_prev = u[0].data();
            const double* u_row_curr = u[1].data();
            const double* u_row_next = u[2].data();

            v_row0[i] = 1.0;
            p_row[0]   = 0.0;
            q_row[0]   = v_row0[i];

            for (int j = 1; j < n-1; ++j)
            {
                const double denom = a * p_row[j-1] + b;
                const double inv   = -c / denom;
                p_row[j] = inv;

                const double t1 = -d * u_row_prev[j] + (1.0 + 2.0 * d) * u_row_curr[j] - f * u_row_next[j] - a * q_row[j-1];
                q_row[j]   = t1 / denom;
            }

            v_rowN[i] = 1.0;

            for (int j = n-2; j >= 1; --j)
            {
                v_rowN[j] = p_row[j] * v_rowN[j+1] + q_row[j];
            }
        }

        /* Second sweep (horizontal) */
#pragma omp for schedule(static)
        for (int i = 1; i < n-1; ++i)
        {
            double* u_row0    = u[0].data();
            double* u_rowN     = u[n-1].data();
            double* p_row      = p[i].data();
            double* q_row      = q[i].data();
            const double* v_row_prev = v[0].data();
            const double* v_row_curr = v[1].data();
            const double* v_row_next = v[2].data();

            u_row0[i] = 1.0;
            p_row[0]   = 0.0;
            q_row[0]   = u_row0[i];

            for (int j = 1; j < n-1; ++j)
            {
                const double denom = d * p_row[j-1] + e;
                const double inv   = -f / denom;
                p_row[j] = inv;

                const double t1 = -a * v_row_prev[j] + (1.0 + 2.0 * a) * v_row_curr[j] - c * v_row_next[j] - d * q_row[j-1];
                q_row[j]   = t1 / denom;
            }

            u_rowN[i] = 1.0;

            for (int j = n-2; j >= 1; --j)
            {
                u_rowN[j] = p_row[j] * u_rowN[j+1] + q_row[j];
            }
        }
    }
}
